# Found it! Let's check the main agent's auth profile
cat /home/gilles/.openclaw/agents/main/agent/auth-profiles.json | python3 -c "
import json,sys
d=json.load(sys.stdin)
for profile_name, profile_data in d.items():
    print(f'=== {profile_name} ===')
    for k,v in profile_data.items():
        if 'token' in k.lower() or 'key' in k.lower() or 'secret' in k.lower():
            val = str(v)
            if len(val) > 20:
                print(f'  {k}: {val[:20]}...{val[-8:]}')
            else:
                print(f'  {k}: {val}')
        else:
            print(f'  {k}: {v}')
    print()
"

